parameters.jsCode:
let parsed = {};

if ($input.item.json.Lead_score !== undefined) {
  parsed = {
    Lead_score: $input.item.json.Lead_score,
    Nivel_urgencia: $input.item.json.Nivel_urgencia,
    Resumen: $input.item.json.Resumen
  };
} else if ($input.item.json.output && $input.item.json.output.Lead_score !== undefined) {
  parsed = $input.item.json.output;
} else if ($input.item.json.text && typeof $input.item.json.text === 'object' && $input.item.json.text.Lead_score !== undefined) {
  parsed = $input.item.json.text;
} else {
  const textToParse = $input.item.json.text || $input.item.json.output || '';
  if (typeof textToParse === 'string' && textToParse.length > 0) {
    try {
      const match = textToParse.match(/\{[\s\S]*\}/);
      if (match) {
        let tempParsed = JSON.parse(match[0]);
        if (tempParsed.__structured___output) {
          parsed = tempParsed.__structured___output;
        } else {
          parsed = tempParsed;
        }
      } else {
        throw new Error("No JSON object found");
      }
    } catch(e) {
      parsed = { Lead_score: 1, Nivel_urgencia: 'Parse Error', Resumen: textToParse };
    }
  } else {
      parsed = { Lead_score: 1, Nivel_urgencia: 'No Data', Resumen: JSON.stringify($input.item.json) };
  }
}

if (parsed.Lead_score !== undefined) {
    parsed.Lead_score = Number(parsed.Lead_score);
}

return { json: { ...$input.item.json, parsed } };
